416	func markLocalInstallOverlay(projectRoot, pluginName string, files []string) (int, error) {
417		if projectRoot == "" {
418			return 0, nil
419		}
420	
421		ctx := context.Background()
422		topOut, err := internalgit.Command(ctx, projectRoot, "rev-parse", "--show-toplevel").Output()
423		if err != nil {
424			return 0, nil
425		}
426		repoRoot := strings.TrimSpace(string(topOut))
427		if repoRoot == "" {
428			return 0, nil
429		}
430	
431		paths := localOverlayPaths(pluginName, files)
432		if len(paths) == 0 {
433			return 0, nil
434		}
435		if err := addLocalOverlayIgnores(repoRoot, paths); err != nil {
436			return 0, err
437		}
438	
439		args := append([]string{"ls-files", "-z", "--"}, paths...)
440		trackedOut, err := internalgit.Command(ctx, repoRoot, args...).Output()
441		if err != nil {
442			return 0, err
443		}
444		var tracked []string
445		for _, p := range strings.Split(string(trackedOut), "\x00") {
446			if p != "" {
447				tracked = append(tracked, p)
448			}
449		}
450		for start := 0; start < len(tracked); start += 100 {
451			end := start + 100
452			if end > len(tracked) {
453				end = len(tracked)
454			}
455			args := append([]string{"update-index", "--skip-worktree", "--"}, tracked[start:end]...)
456			if err := internalgit.Command(ctx, repoRoot, args...).Run(); err != nil {
457				return 0, err
458			}
459		}
460		return len(tracked), nil
461	}
