566	func addLocalOverlayIgnores(repoRoot string, paths []string) error {
567		excludePath := filepath.Join(repoRoot, ".git", "info", "exclude")
568		existing, _ := os.ReadFile(excludePath)
569		text := string(existing)
570	
571		var additions []string
572		for _, p := range paths {
573			pattern := filepath.ToSlash(p)
574			candidates := []string{pattern}
575			if !strings.HasSuffix(pattern, "/") {
576				candidates = append(candidates, pattern+"/")
577			}
578			for _, candidate := range candidates {
579				if !strings.Contains(text, "\n"+candidate+"\n") && !strings.HasPrefix(text, candidate+"\n") {
580					additions = append(additions, candidate)
581				}
582			}
583		}
584		if len(additions) == 0 {
585			return nil
586		}
587	
588		var sb strings.Builder
589		if len(existing) > 0 && !strings.HasSuffix(text, "\n") {
590			sb.WriteString("\n")
591		}
592		if !strings.Contains(text, "# DDx local plugin overlays") {
593			sb.WriteString("\n# DDx local plugin overlays\n")
594		}
595		for _, pattern := range additions {
596			sb.WriteString(pattern)
597			sb.WriteString("\n")
598		}
599		return os.WriteFile(excludePath, append(existing, []byte(sb.String())...), 0o644)
600	}
