602	// copyDirTree copies the source directory tree into dst as real files,
603	// returning the list of written file paths (relative to cwd).
604	func copyDirTree(src, dst string) ([]string, error) {
605		var written []string
606		err := filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
607			if err != nil {
608				return err
609			}
610			rel, relErr := filepath.Rel(src, path)
611			if relErr != nil {
612				return relErr
613			}
614			if shouldSkipLocalInstallPath(rel, info) {
615				if info.IsDir() {
616					return filepath.SkipDir
617				}
618				return nil
619			}
620			target := filepath.Join(dst, rel)
621			if info.IsDir() {
622				return os.MkdirAll(target, 0o755)
623			}
624			if info.Mode()&os.ModeSymlink != 0 {
625				// Skip plugin-source symlinks — never materialize.
626				return nil
627			}
628			if !info.Mode().IsRegular() {
629				return nil
630			}
631			if err := os.MkdirAll(filepath.Dir(target), 0o755); err != nil {
632				return err
633			}
634			in, err := os.Open(path)
635			if err != nil {
636				return err
637			}
638			defer func() { _ = in.Close() }()
639			out, err := os.OpenFile(target, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, info.Mode())
640			if err != nil {
641				return err
642			}
643			if _, copyErr := io.Copy(out, in); copyErr != nil {
644				_ = out.Close()
645				return copyErr
646			}
647			if err := out.Close(); err != nil {
648				return err
649			}
650			written = append(written, target)
651			return nil
652		})
653		return written, err
654	}
