12	// Options controls Install behavior.
13	type Options struct {
14		// Force overwrites pre-existing real-file destinations. When false, existing
15		// real-file skill directories are preserved (per-skill skip). Pre-existing
16		// symlink destinations are ALWAYS removed regardless of Force.
