20	// Install copies skills from src into <projectRoot>/.agents/skills/<name>/ and
21	// <projectRoot>/.claude/skills/<name>/ as real files. Never creates symlinks.
22	//
23	// Source layouts:
24	//   - Top-level skill dirs (embed.FS bootstrap): src has "<skillName>/..."
25	//   - Plugin layout (os.DirFS over plugin root): src has ".agents/skills/<skillName>";
26	//     when that path is a broken symlink (tarball authored with symlinks),
27	//     falls back to "skills/<skillName>".
28	func Install(src fs.FS, projectRoot string, opts Options) error {
29		if projectRoot == "" {
30			return errors.New("skills.Install: projectRoot is empty")
31		}
32	
33		skillNames, sources, err := discoverSkills(src)
34		if err != nil {
35			return fmt.Errorf("discover skills: %w", err)
36		}
37	
38		for _, name := range skillNames {
39			if err := validateSkillName(name); err != nil {
40				return err
41			}
42		}
43	
44		targets := []string{
45			filepath.Join(projectRoot, ".agents", "skills"),
46			filepath.Join(projectRoot, ".claude", "skills"),
47		}
48	
49		// Pre-flight: validate every destination resolves inside projectRoot.
50		// Done before any write so traversal/escape inputs error out cleanly.
51		absRoot, err := filepath.Abs(projectRoot)
52		if err != nil {
53			return fmt.Errorf("resolve projectRoot: %w", err)
54		}
55		for _, target := range targets {
56			for _, name := range skillNames {
57				destDir := filepath.Join(target, name)
58				// Symlinks are always removed and replaced with real files; skip the
59				// within-root check for them (the replacement write will be inside
60				// the root). This handles pre-migration symlinks pointing to
61				// locations outside the project root.
62				if info, err := os.Lstat(destDir); err == nil && info.Mode()&os.ModeSymlink != 0 {
63					continue
64				}
65				if err := assertWithinRoot(destDir, absRoot); err != nil {
66					return err
67				}
68			}
69		}
70	
71		// Ensure target parents exist after validation.
72		for _, t := range targets {
73			if err := os.MkdirAll(t, 0o755); err != nil {
74				return fmt.Errorf("create %s: %w", t, err)
75			}
76			// Reject if target itself is a symlink escaping projectRoot.
77			if err := assertWithinRoot(t, absRoot); err != nil {
78				return err
79			}
80		}
81	
82		for i, name := range skillNames {
83			srcSub := sources[i]
84			for _, target := range targets {
85				destDir := filepath.Join(target, name)
86				info, lerr := os.Lstat(destDir)
87				if lerr == nil {
88					if info.Mode()&os.ModeSymlink != 0 {
89						// Symlink: always remove and replace, regardless of Force.
90						if err := os.Remove(destDir); err != nil {
91							return fmt.Errorf("remove pre-existing symlink %s: %w", destDir, err)
92						}
93					} else if !opts.Force {
94						// Real-file destination + !Force: skip per-skill (whole dir).
95						continue
96					} else {
97						// Real-file destination + Force: overwrite by removing first.
98						if err := os.RemoveAll(destDir); err != nil {
99							return fmt.Errorf("remove existing dir %s: %w", destDir, err)
100						}
101					}
102				}
103				if err := copyFromFS(srcSub, destDir); err != nil {
104					return fmt.Errorf("copy skill %q: %w", name, err)
105				}
106			}
107		}
108	
109		return nil
