228	func pathHasPrefix(p, prefix string) bool {
229		if p == prefix {
230			return true
231		}
232		sep := string(filepath.Separator)
233		if !strings.HasSuffix(prefix, sep) {
234			prefix += sep
235		}
236		return strings.HasPrefix(p, prefix)
237	}
