191	func installPathContainsAny(parent string, files []string) bool {
192		parent = filepath.ToSlash(strings.TrimSuffix(parent, string(filepath.Separator)))
193		parent = strings.TrimSuffix(parent, "/")
194		if parent == "" {
195			return false
196		}
197		prefix := parent + "/"
198		for _, f := range files {
199			f = filepath.ToSlash(f)
200			if strings.HasPrefix(f, prefix) {
201				return true
202			}
203		}
204		return false
205	}
