250	// installLocal installs a plugin from a local directory into the current
251	// checkout as a developer overlay. It intentionally does not update installed
252	// state and does not auto-commit: the recorded plugin pin remains whatever the
253	// project already declares, while this machine can test a local plugin tree.
254	func (f *CommandFactory) installLocal(name, localPath string, force bool, out io.Writer) error {
255		// Resolve to absolute path.
256		absPath, err := filepath.Abs(localPath)
257		if err != nil {
258			return fmt.Errorf("resolving path %s: %w", localPath, err)
259		}
260		if _, err := os.Stat(absPath); os.IsNotExist(err) {
261			return fmt.Errorf("local path does not exist: %s", absPath)
262		}
263	
264		// Load package.yaml when present so local installs honor the manifest
265		// contract, but keep the built-in registry as a compatibility fallback.
266		reg := registry.BuiltinRegistry()
267		fallbackPkg, _ := reg.Find(name)
268	
269		pkg, manifestMissing, manifestIssues, manifestErr := registry.LoadPackageManifestWithFallback(absPath, fallbackPkg)
270		if manifestErr == nil {
271			if strings.TrimSpace(pkg.Name) != "" && pkg.Name != name {
272				return fmt.Errorf("local package name %q does not match package.yaml name %q", name, pkg.Name)
273			}
274		} else {
275			if os.IsNotExist(manifestErr) && manifestMissing {
276				if pkg == nil {
277					pkg = &registry.Package{
278						Name:        name,
279						Version:     "local",
280						Description: "local plugin package",
281						Type:        registry.PackageTypePlugin,
282						Source:      absPath,
283					}
284				}
285			} else if len(manifestIssues) > 0 {
286				return fmt.Errorf("validating package manifest: %w", manifestErr)
287			} else {
288				return fmt.Errorf("loading package manifest: %w", manifestErr)
289			}
290		}
291	
292		if pkg == nil {
293			pkg = &registry.Package{
294				Name:        name,
295				Version:     "local",
296				Description: "local plugin package",
297				Type:        registry.PackageTypePlugin,
