// TestPluginInstallLocalDDxLibrarySymlinksSkills proves the plan-2026-05-13
// development workflow: pointing `ddx plugin install ddx --local <repo>/library
// --force` at the canonical `library/` package yields project-local skill
// overlays as symlinks back into `library/skills/ddx` (no copied mirrors).
func TestPluginInstallLocalDDxLibrarySymlinksSkills(t *testing.T) {
	libraryDir, err := filepath.Abs(filepath.Join("..", "..", "library"))
	require.NoError(t, err)
	require.FileExists(t, filepath.Join(libraryDir, "package.yaml"),
		"canonical library/package.yaml must exist")
	require.FileExists(t, filepath.Join(libraryDir, "skills", "ddx", "SKILL.md"),
		"canonical library/skills/ddx/SKILL.md must exist")

	workDir := t.TempDir()
	homeDir := t.TempDir()
	t.Setenv("HOME", homeDir)

	factory := NewCommandFactory(workDir)
	output, err := executeCommand(factory.NewRootCommand(), "install", "ddx", "--local", libraryDir, "--force")
	require.NoError(t, err, output)

	expectedTarget := filepath.Join(libraryDir, "skills", "ddx")
	assertLocalSymlink(t, filepath.Join(workDir, ".agents", "skills", "ddx"), expectedTarget)
	assertLocalSymlink(t, filepath.Join(workDir, ".claude", "skills", "ddx"), expectedTarget)
	assertLocalSymlink(t, filepath.Join(workDir, ".ddx", "plugins", "ddx"), libraryDir)

	// Sanity: the symlink resolves to a real SKILL.md, proving the developer
	// overlay surfaces live edits from library/skills/ddx without a copied
	// mirror.
	for _, surface := range []string{".agents", ".claude"} {
		assert.FileExists(t, filepath.Join(workDir, surface, "skills", "ddx", "SKILL.md"),
			"%s/skills/ddx/SKILL.md must resolve through the developer symlink", surface)
	}
}

