func installLocalSkillSymlinks(pluginRoot, projectRoot string, mappings []registry.InstallMapping, force bool) ([]string, error) {
	sources, err := localSkillSourceMappings(pluginRoot, mappings)
	if err != nil {
		return nil, err
	}
	if len(sources) == 0 {
		return nil, nil
	}

	// Mirror every discovered source into both harness surfaces, deduping by
	// (surface, skill name) so multiple manifest mappings pointing at the same
	// source don't double-symlink.
	seen := map[string]bool{}
	var written []string
	for _, source := range sources {
		entries, err := os.ReadDir(source.dir)
		if err != nil {
			if os.IsNotExist(err) {
				continue
			}
			return nil, err
		}
		for _, entry := range entries {
			if !entry.IsDir() && entry.Type()&os.ModeSymlink == 0 {
				continue
			}
			name := entry.Name()
			src := filepath.Join(source.dir, name)
			if _, err := os.Stat(filepath.Join(src, "SKILL.md")); err != nil {
				return nil, fmt.Errorf("%s: missing SKILL.md: %w", src, err)
			}
			for _, surface := range source.surfaces {
				key := surface + "/" + name
				if seen[key] {
					continue
				}
				seen[key] = true
				dst := filepath.Join(projectRoot, filepath.FromSlash(surface), name)
				if err := prepareSymlinkTarget(dst, force); err != nil {
					return nil, err
				}
				if err := os.MkdirAll(filepath.Dir(dst), 0o755); err != nil {
					return nil, fmt.Errorf("creating skills dir: %w", err)
				}
				target, err := filepath.Rel(filepath.Dir(dst), src)
				if err != nil {
					target = src
				}
				if err := os.Symlink(target, dst); err != nil {
					return nil, fmt.Errorf("linking skill %s -> %s: %w", dst, target, err)
				}
				written = append(written, filepath.Join(filepath.FromSlash(surface), name))
			}
		}
	}
	return written, nil
}

// localSkillSource pairs a discovered source directory inside the plugin root
// with the list of project-relative harness surfaces it should be mirrored to.
type localSkillSource struct {
	dir      string
	surfaces []string
}

// localSkillSourceMappings resolves the package's declared skill mappings
// against the plugin root, falling back to filesystem discovery when the
// manifest does not specify sources. Always installs to both .agents/skills
// and .claude/skills so the harness discovery paths see the same skills.
func localSkillSourceMappings(pluginRoot string, mappings []registry.InstallMapping) ([]localSkillSource, error) {
	surfaces := []string{".agents/skills", ".claude/skills"}

	if len(mappings) > 0 {
		bySource := map[string]bool{}
		var ordered []string
		for _, m := range mappings {
			src := strings.TrimSpace(m.Source)
			if src == "" {
				continue
			}
			src = strings.TrimSuffix(filepath.ToSlash(src), "/")
			if bySource[src] {
				continue
			}
			bySource[src] = true
			ordered = append(ordered, src)
		}
		var out []localSkillSource
		for _, src := range ordered {
			full := filepath.Join(pluginRoot, filepath.FromSlash(src))
			if info, err := os.Stat(full); err != nil || !info.IsDir() {
				if err != nil && !os.IsNotExist(err) {
					return nil, err
				}
				continue
			}
			out = append(out, localSkillSource{dir: full, surfaces: surfaces})
		}
		if len(out) > 0 {
			return out, nil
		}
	}

	for _, candidate := range []string{
		filepath.Join(pluginRoot, ".agents", "skills"),
		filepath.Join(pluginRoot, "skills"),
	} {
		entries, err := os.ReadDir(candidate)
		if err == nil && len(entries) > 0 {
			return []localSkillSource{{dir: candidate, surfaces: surfaces}}, nil
		}
		if err != nil && !os.IsNotExist(err) {
			return nil, err
		}
	}
	return nil, nil
}

